import{_ as r,a as i,b as a}from"./chunks/0_H84UsJVgH3V5j96h.14oI3MBq.js";import{_ as t,c as o,o as n,ag as s}from"./chunks/framework.S-Qvb3wi.js";const I=JSON.parse('{"title":"AI 競技場","description":"","frontmatter":{},"headers":[],"relativePath":"zh-TW/AI-Arena.md","filePath":"zh-TW/AI-Arena.md"}'),e={name:"zh-TW/AI-Arena.md"};function g(d,l,h,u,p,c){return n(),o("div",null,l[0]||(l[0]=[s('<h1 id="ai-競技場" tabindex="-1">AI 競技場 <a class="header-anchor" href="#ai-競技場" aria-label="Permalink to &quot;AI 競技場&quot;">​</a></h1><p><strong>DGrid AI 競技場</strong>是DGrid平台內的專屬樞紐，使用者可在此協助評估並優化DGrid的AI模型，並透過貢獻獲取鏈上獎勵。</p><p>完成簡單的每日「AI 對決」任務並邀請新用戶加入，參與者可：</p><ul><li>比較真實的AI模型回應，並指出哪個回應更佳</li><li>每項決策與推薦行為均可獲得積分</li><li>将積分兌換為<strong>USDT</strong></li><li>參與<strong>每週排行榜</strong>競賽，瓜分共享獎池</li></ul><p>DGrid AI 競技場不僅是遊戲化層級設計，更是DGrid AI基礎架構的核心組件，透過社群判斷實現以下目標：</p><ul><li>評估模型品質</li><li>引導模型優化與部署方向</li><li>持續讓DGrid AI與真實用戶的期望保持一致</li></ul><h2 id="核心概念" tabindex="-1">核心概念 <a class="header-anchor" href="#核心概念" aria-label="Permalink to &quot;核心概念&quot;">​</a></h2><h4 id="ai-競技場-1" tabindex="-1">AI 競技場 <a class="header-anchor" href="#ai-競技場-1" aria-label="Permalink to &quot;AI 競技場&quot;">​</a></h4><p><strong>AI 競技場</strong>是DGrid平台中所有AI獎勵與評估活動的入口，包含以下核心模組：</p><ul><li>​<strong>AI 對決</strong>：每日任務，使用者需比較AI回覆內容</li><li>​<strong>積分與獎勵</strong>：追蹤已獲積分、兌換紀錄及排行榜排名</li></ul><p>可透過DGrid介面進入AI競技場，或直接造訪以下網址： <a href="https://dgrid.ai/arena" target="_blank" rel="noreferrer"><code>https://dgrid.ai/arena</code></a></p><h4 id="ai-對決" tabindex="-1">AI 對決 <a class="header-anchor" href="#ai-對決" aria-label="Permalink to &quot;AI 對決&quot;">​</a></h4><p><strong>AI 對決</strong>是DGrid AI競技場的核心互動流程。使用者需：</p><ul><li>接收隨機的問題或提示語</li><li>查看<strong>兩個匿名的AI模型回應</strong></li><li>選擇認為更優的回應</li></ul><p>每項決策不僅能獲得積分，還會被納入DGrid的模型評估與訓練流程。</p><h4 id="積分" tabindex="-1">積分 <a class="header-anchor" href="#積分" aria-label="Permalink to &quot;積分&quot;">​</a></h4><p><strong>積分</strong>是DGrid AI競技場中衡量貢獻度的內部指標，具體規則如下：</p><ul><li>獲取方式： <ul><li>完成每日AI對決任務</li><li>推薦新用戶加入</li></ul></li><li>使用方式： <ul><li>直接兌換為USDT</li><li>決定每週排行榜獎池的瓜分比例</li></ul></li></ul><h4 id="獎勵-usdt-與每週獎池" tabindex="-1">獎勵（USDT 與每週獎池） <a class="header-anchor" href="#獎勵-usdt-與每週獎池" aria-label="Permalink to &quot;獎勵（USDT 與每週獎池）&quot;">​</a></h4><p>DGrid AI競技場以<strong>真實的鏈上價值</strong>回饋參與者：</p><ul><li>依據累積積分<strong>直接兌換USDT</strong></li><li>從<strong>300美元共享獎池</strong>中獲得<strong>每週排行榜獎勵</strong></li></ul><h2 id="ai-對決運作機制" tabindex="-1">AI 對決運作機制 <a class="header-anchor" href="#ai-對決運作機制" aria-label="Permalink to &quot;AI 對決運作機制&quot;">​</a></h2><h3 id="每日任務" tabindex="-1">每日任務 <a class="header-anchor" href="#每日任務" aria-label="Permalink to &quot;每日任務&quot;">​</a></h3><ul><li>每位使用者每日最多可完成<strong>5項每日任務</strong>。</li><li>每項任務設計為<strong>快速且直觀</strong>，僅需耗費少量時間。</li><li>任務每日重置，鼓勵使用者持續參與。</li></ul><h3 id="任務流程" tabindex="-1">任務流程 <a class="header-anchor" href="#任務流程" aria-label="Permalink to &quot;任務流程&quot;">​</a></h3><p>每項任務包含以下步驟：</p><ol><li><strong>提示語展示</strong></li></ol><ul><li>向使用者展示一則<strong>隨機問題或提示語</strong>。</li></ul><ol start="2"><li><strong>兩個匿名AI回應</strong></li></ol><ul><li>提示語下方會呈現<strong>兩個AI回應</strong>，分別來自不同的模型（潛在）。</li><li>模型資訊為匿名狀態，僅可查看回應內容本身。</li></ul><ol start="3"><li><strong>使用者選擇</strong></li></ol><ul><li>使用者仔細閱讀兩個回應內容。</li><li>選擇符合以下標準的回應： <ul><li>更契合提示語需求</li><li>更符合自身期望或需求</li></ul></li></ul><ol start="4"><li><strong>依社群共識給予積分</strong></li></ol><ul><li>當足夠多的使用者完成投票後，該任務會形成<strong>社群多數意見</strong>。</li><li>使用者的獎勵取決於其選擇是否與多數意見一致（詳情見下一節）。</li></ul><h3 id="在模型訓練與評估中的角色" tabindex="-1">在模型訓練與評估中的角色 <a class="header-anchor" href="#在模型訓練與評估中的角色" aria-label="Permalink to &quot;在模型訓練與評估中的角色&quot;">​</a></h3><p>AI對決中的每一票都是DGrid AI網路的<strong>數據點</strong>。DGrid彙總這些使用者選擇，用以：</p><ul><li><strong>評估模型效能</strong>：識別持續產生優質回應的模型</li><li><strong>理解使用者偏好</strong>：使用者在清晰度、實用性、安全性與相關性上的價值取向</li><li><strong>引導模型迭代</strong>：優先推廣表現更佳的模型；指導微調策略與部署決策</li></ul><p>透過大規模運作，每日數千名使用者的數千次微決策會形成強大的<strong>人工回饋信號</strong>，使DGrid能夠：</p><ul><li>打造更<strong>可靠、符合人類需求的AI大型語言模型（LLM）網路</strong></li><li>提升對多元問題類型的適應性與穩健性</li><li>跳脫靜態基準測試，實現<strong>持續的即時評估</strong></li></ul><h2 id="積分系統" tabindex="-1">積分系統 <a class="header-anchor" href="#積分系統" aria-label="Permalink to &quot;積分系統&quot;">​</a></h2><h3 id="積分獲取方式" tabindex="-1">積分獲取方式 <a class="header-anchor" href="#積分獲取方式" aria-label="Permalink to &quot;積分獲取方式&quot;">​</a></h3><p>在DGrid AI競技場中，主要有兩種獲取積分的方式：</p><ol><li><strong>AI 對決每日任務</strong></li></ol><ul><li>每項任務可獲得<strong>5–10積分</strong>： <ul><li>若選擇與<strong>社群多數意見</strong>一致，獲得<strong>10積分</strong></li><li>若選擇與多數意見<strong>不一致</strong>，獲得<strong>5積分</strong></li></ul></li><li>參與即無「錯誤」之分： <ul><li>即使選擇與多數意見不同，仍可獲得積分</li><li>每一票均被視為珍貴的回饋</li></ul></li><li>透過每日<strong>最多5項任務</strong>，使用者可穩定累積積分，同時為模型訓練貢獻力量。</li></ul><ol start="2"><li><strong>推薦積分</strong></li></ol><ul><li>使用者可邀請他人加入DGrid AI競技場。</li><li>每成功邀請一位<strong>有效新用戶</strong>，推薦者可獲得最高<strong>100積分</strong>。</li><li>推薦機制讓使用者可透過<strong>社群擴張</strong>而非僅依自身活動來提升獎勵。</li></ul><h3 id="積分使用方式" tabindex="-1">積分使用方式 <a class="header-anchor" href="#積分使用方式" aria-label="Permalink to &quot;積分使用方式&quot;">​</a></h3><p><strong>總積分</strong>具備兩大核心用途：</p><ul><li><strong>直接兌換USDT</strong></li><li><strong>排行榜排名與每週獎池瓜分資格</strong></li></ul><p>透過任務與推薦獲得的積分越多：</p><ul><li>可兌換的USDT越多</li><li>每週排行榜的相對排名越高</li><li>每週獎池的瓜分比例越大</li></ul><h2 id="獎勵模型" tabindex="-1">獎勵模型 <a class="header-anchor" href="#獎勵模型" aria-label="Permalink to &quot;獎勵模型&quot;">​</a></h2><h3 id="直接兌換-積分-→-usdt" tabindex="-1">直接兌換：積分 → USDT <a class="header-anchor" href="#直接兌換-積分-→-usdt" aria-label="Permalink to &quot;直接兌換：積分 → USDT&quot;">​</a></h3><p>使用者可依固定匯率將積分直接兌換為<strong>USDT</strong>：</p><ul><li>​<strong>兌換匯率</strong>​： <ul><li>`1,000 積分 = 1 USDT`</li></ul></li><li>​<strong>最低兌換門檻</strong>​： <ul><li><strong>1,000 積分</strong>（相當於1 USDT）</li></ul></li><li>​<strong>兌換結果</strong>​： <ul><li>兌換完成後，USDT會直接轉入使用者綁定至DGrid的錢包。</li></ul></li></ul><p>這一機制使付出與收穫之間具備<strong>清晰且透明</strong>的對應關係：</p><blockquote><p>完成更多任務 + 推薦更多用戶 → 獲得更多積分 → 錢包中的USDT更多。</p></blockquote><h3 id="每週排行榜-競爭性獎勵" tabindex="-1">每週排行榜：競爭性獎勵 <a class="header-anchor" href="#每週排行榜-競爭性獎勵" aria-label="Permalink to &quot;每週排行榜：競爭性獎勵&quot;">​</a></h3><p>除直接兌換外，DGrid AI競技場還設有<strong>每週排行榜</strong>，用以獎勵最活躍、貢獻最大的參與者。</p><ul><li>​<strong>每週獎池</strong>​： <ul><li>每週<strong>300美元</strong></li></ul></li><li>​<strong>分配機制</strong>​： <ul><li>排名靠前的參與者瓜分<strong>300美元</strong>獎池</li><li>獎勵與<strong>每週獲得的積分</strong>成正比： <ul><li>該週獲得的積分越多</li><li>瓜分的<strong>300美元</strong>獎池比例越大</li></ul></li></ul></li></ul><h3 id="獎勵結構總結" tabindex="-1">獎勵結構總結 <a class="header-anchor" href="#獎勵結構總結" aria-label="Permalink to &quot;獎勵結構總結&quot;">​</a></h3><ul><li><strong>休閒使用者</strong><ul><li>透過持續完成每日任務獲得獎勵</li><li>可逐步將積分兌換為USDT</li></ul></li><li><strong>核心使用者與頂級貢獻者</strong><ul><li>可同時享有： <ul><li>直接USDT兌換獎勵</li><li>來自排行榜的額外收益</li></ul></li></ul></li></ul><p>這一<strong>雙重獎勵機制</strong>確保所有參與行為都能得到認可，同時<strong>激勵使用者持續且高價值地參與</strong>。</p><h2 id="開始使用dgrid-ai-競技場" tabindex="-1">開始使用DGrid AI 競技場 <a class="header-anchor" href="#開始使用dgrid-ai-競技場" aria-label="Permalink to &quot;開始使用DGrid AI 競技場&quot;">​</a></h2><h3 id="步驟1-進入ai-競技場" tabindex="-1">步驟1：進入AI 競技場 <a class="header-anchor" href="#步驟1-進入ai-競技場" aria-label="Permalink to &quot;步驟1：進入AI 競技場&quot;">​</a></h3><p>造訪​<strong>AI 競技場</strong>​：<a href="https://dgrid.ai/arena" target="_blank" rel="noreferrer"><code>https://dgrid.ai/arena</code></a>。</p><p>進入後：</p><ul><li><strong>綁定錢包</strong></li><li><strong>啟用競技場使用權限</strong></li></ul><p><img src="'+r+'" alt=""></p><h3 id="步驟2-開始ai-對決" tabindex="-1">步驟2：開始AI 對決 <a class="header-anchor" href="#步驟2-開始ai-對決" aria-label="Permalink to &quot;步驟2：開始AI 對決&quot;">​</a></h3><p>點擊**「開始AI 對決」<strong>。任務啟動後：你會看到一則</strong>問題/提示語<strong>與​</strong>兩個匿名AI回應**​。仔細閱讀兩個回應，選擇你認為更優的一個。每完成一項任務：</p><ul><li>依是否與社群共識一致，可獲得​<strong>5–10積分</strong>​。</li><li>每日最多可完成<strong>5項任務</strong>。</li></ul><p><img src="'+i+'" alt=""></p><h3 id="步驟3-每日堅持參與" tabindex="-1">步驟3：每日堅持參與 <a class="header-anchor" href="#步驟3-每日堅持參與" aria-label="Permalink to &quot;步驟3：每日堅持參與&quot;">​</a></h3><p>每日回歸平台：</p><ul><li>完成<strong>5項每日任務</strong></li><li>累積更多積分</li><li>持續為訓練與優化DGrid AI貢獻力量</li></ul><p><img src="'+a+'" alt=""></p><h3 id="步驟4-邀請好友-推薦計畫" tabindex="-1">步驟4：邀請好友（推薦計畫） <a class="header-anchor" href="#步驟4-邀請好友-推薦計畫" aria-label="Permalink to &quot;步驟4：邀請好友（推薦計畫）&quot;">​</a></h3><p>透過DGrid介面中的推薦機制，分享DGrid AI競技場給你的社交圈。每成功邀請一位​<strong>有效新用戶</strong>​，你將獲得最高​<strong>100積分</strong>​。</p><p>推薦計畫有助於：</p><ul><li>壯大<strong>DGrid社群</strong></li><li>提升<strong>AI對決回饋的數量與多樣性</strong></li><li>增加個人積分與獎勵</li></ul><h3 id="步驟5-兌換積分-追蹤排行榜排名" tabindex="-1">步驟5：兌換積分 &amp; 追蹤排行榜排名 <a class="header-anchor" href="#步驟5-兌換積分-追蹤排行榜排名" aria-label="Permalink to &quot;步驟5：兌換積分 &amp; 追蹤排行榜排名&quot;">​</a></h3><p>在DGrid介面中查看你的<strong>總積分</strong>。當積分達到至少​<strong>1,000分</strong>​時，你可依<code>1,000 : 1 USDT</code>的匯率兌換為<strong>USDT</strong>。查看<strong>每週排行榜</strong>可瞭解：</p><ul><li>你相較於其他參與者的排名</li><li>你可瓜分的<strong>300美元</strong>每週獎池潛在比例</li></ul><h2 id="dgrid-ai-競技場的核心價值" tabindex="-1">DGrid AI 競技場的核心價值 <a class="header-anchor" href="#dgrid-ai-競技場的核心價值" aria-label="Permalink to &quot;DGrid AI 競技場的核心價值&quot;">​</a></h2><p>DGrid AI 競技場是建構於DGrid AI基礎架構之上的<strong>協同智慧層級</strong>，旨在讓DGrid AI網路具備以下特質：</p><ul><li>更<strong>符合</strong>真實用戶的期望</li><li>對多元問題與內容類型具備更高的<strong>穩健性</strong></li><li>​<strong>持續優化</strong>​，由即時的真實世界回饋驅動</li></ul><h3 id="大規模人工判斷" tabindex="-1">大規模人工判斷 <a class="header-anchor" href="#大規模人工判斷" aria-label="Permalink to &quot;大規模人工判斷&quot;">​</a></h3><p>透過整合以下要素：</p><ul><li>數千場AI對決中的人工判斷</li><li>由社群驅動的模型品質評估</li><li>與USDT綁定的透明鏈上獎勵機制</li></ul><p>DGrid得以：</p><ul><li>決定優先推廣與部署的模型</li><li>瞭解使用者對「清晰、實用、安全、相關」的價值取向</li><li>決定如何以及何時在生態系中推出新功能</li></ul><p>每一分積的背後，不僅是數字——更是引導決策的<strong>信號</strong>：</p><ul><li>哪些模型在正面對決中「脫穎而出」</li><li>模型應如何進行<strong>微調</strong></li><li>哪些行為應被<strong>強化或抑制</strong></li></ul><p>透過這種方式，​<strong>每位使用者的選擇都成為投票，助力打造更好的AI</strong>​。</p><h2 id="常見問題" tabindex="-1">常見問題 <a class="header-anchor" href="#常見問題" aria-label="Permalink to &quot;常見問題&quot;">​</a></h2><h4 id="ai-對決中有「錯誤」的選擇嗎" tabindex="-1">AI 對決中有「錯誤」的選擇嗎？ <a class="header-anchor" href="#ai-對決中有「錯誤」的選擇嗎" aria-label="Permalink to &quot;AI 對決中有「錯誤」的選擇嗎？&quot;">​</a></h4><p>沒有。參與即無「錯誤」之分。</p><ul><li>若選擇與​<strong>社群多數意見</strong>​一致，獲得​<strong>10積分</strong>​。</li><li>若選擇與多數意見<strong>不一致</strong>，仍可獲得​<strong>5積分</strong>​。</li></ul><p>每一項決定都被視為模型評估的珍貴信號。</p><h4 id="我每天可完成多少項任務" tabindex="-1">我每天可完成多少項任務？ <a class="header-anchor" href="#我每天可完成多少項任務" aria-label="Permalink to &quot;我每天可完成多少項任務？&quot;">​</a></h4><p>你每日最多可在AI對決中完成<strong>5項每日任務</strong>。</p><h4 id="如何獲得推薦積分" tabindex="-1">如何獲得推薦積分？ <a class="header-anchor" href="#如何獲得推薦積分" aria-label="Permalink to &quot;如何獲得推薦積分？&quot;">​</a></h4><p>透過DGrid介面中的推薦機制，邀請他人加入DGrid AI競技場。每成功邀請一位​<strong>有效新用戶</strong>​，你將獲得最高​<strong>100積分</strong>​。</p><h4 id="積分如何兌換為usdt" tabindex="-1">積分如何兌換為USDT？ <a class="header-anchor" href="#積分如何兌換為usdt" aria-label="Permalink to &quot;積分如何兌換為USDT？&quot;">​</a></h4><ul><li>積分兌換匯率固定為 <code>1,000 積分 = 1 USDT</code>。</li><li>最低兌換門檻為<strong>1,000積分</strong>。</li><li>兌換完成後，​<strong>USDT會直接發送至你綁定的錢包</strong>​。</li></ul><h4 id="每週排行榜如何運作" tabindex="-1">每週排行榜如何運作？ <a class="header-anchor" href="#每週排行榜如何運作" aria-label="Permalink to &quot;每週排行榜如何運作？&quot;">​</a></h4><ul><li>DGrid每週會配置​<strong>300美元獎池</strong>​。</li><li>使用者依據​<strong>該週獲得的積分</strong>​進行排名。</li><li>獎池按比例分配：該週積分越多 → 瓜分的​<strong>300美元</strong>​比例越大。</li></ul><h4 id="我的參與如何優化dgrid-ai" tabindex="-1">我的參與如何優化DGrid AI？ <a class="header-anchor" href="#我的參與如何優化dgrid-ai" aria-label="Permalink to &quot;我的參與如何優化DGrid AI？&quot;">​</a></h4><p>你的投票：</p><ul><li>告知DGrid使用者偏好哪些AI回應</li><li>協助識別在真實場景中表現最佳的模型</li><li>提供持續性回饋，用以指導：模型篩選；微調策略；安全與品質優化</li></ul>',111)]))}const q=t(e,[["render",g]]);export{I as __pageData,q as default};
